Taking all above into account suggest to try this code:
```
def get_structured_data_ttp(raw_output, template=None, ttp_res_kwarg={}):
    """
    Convert raw CLI output to structured data using TTP template.
    You can use a straight TextFSM file i.e. specify "template"
    """
    if not TTP_INSTALLED:
        msg = "\nTTP is not installed. Please PIP install ttp:\n" "pip install ttp\n"
        raise ValueError(msg)

    if template:
        try:
            ttp_parser = ttp(data=raw_output, template=template)
            ttp_parser.parse(one=True) # force to parse in single process
            # print(ttp_parser.result(format="json")[0])
            return ttp_parser.result(**ttp_res_kwarg)
        except Exception:
            return raw_output
    else:
        raise ValueError(f"Template not found: {template}")
```

