```
std::vector<rpc::GcsNodeInfo> node_infos;
auto call_function = [this, request, &node_infos]() {
  auto promise = std::promise<bool>();
  auto future = promise.get_future();
  client_->GetAllNodesInfo(
          request, [p = std::move(promise), &node_infos](const Status &status,
                                           const rpc::GetAllNodesInfoReply &reply) mutable  {
            RAY_CHECK_OK(status);
            for (int index = 0; index < reply.node_infos_size(); ++index) {
              node_infos.push_back(reply.node_infos(index));
            }
            p->set_value(true);
          });
  return future;
};
WaitReady(call_function, timeout_ms_);
return node_infos;
```

