                setattr(self, response_field_name.decode(), response[response_field_name])
            else:
                setattr(self, response_field_name, response[response_field_name])

class CrudError():
    def __init__(self, response):
        assert isinstance(response, (str, bytes))
        self.str = response
        self.err = response
